sql:
SELECT name
FROM startups
WHERE status = 'operating' AND city = 'Mumbai' AND country_code = 'IND';

SELECT COUNT(*) AS operating_startups
FROM startups
WHERE status = 'operating';

SELECT SUM(raised_amount_usd) AS total_raised
FROM funding_rounds
WHERE funding_stage = 'series A';

SELECT name, homepage_url, number_of_employees, founded_at
FROM startups
WHERE status = 'operating' AND number_of_employees > 10;

external_knowledge:
- Funding rounds exceeding $1 million refers to significant investments in startups; 
- The average funding amount provides insight into the level of investment within each industry; 
- Industries with at least one funding round are considered to have some level of investment activity.

sql:
SELECT name, founded_at 
FROM startups 
ORDER BY founded_at ASC;
